CommonData.BannerCustomCSS:
/* Banner */
#onetrust-banner-sdk {
  background: var(--blue-100, #f0f4ff) !important;
  width: 410px !important;
  max-width: calc(100% - 32px) !important;
  padding: 24px !important;
  border-radius: 0px !important;
  left: 16px !important;
  right: 16px !important;
}
#onetrust-banner-sdk * {
  color: var(--black-600, #211d1e) !important;
}

#onetrust-banner-sdk .ot-sdk-container {
    position: initial !important;
}

/* Header - not used */
#onetrust-banner-sdk .banner-header {
  display: none !important;
}

/* Shadow */
#onetrust-banner-sdk.otFloatingRoundedCorner {
  border-radius: 10px !important;
  box-shadow:
    0 4px 13px rgba(0, 0, 0, 0.13),
    0 3px 8px rgba(0, 0, 0, 0.09),
    0 1px 4px rgba(0, 0, 0, 0.09) !important;
}

/* Typography */
#onetrust-banner-sdk * {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto,
    "Helvetica Neue", Arial, "Noto Sans", sans-serif, "Apple Color Emoji",
    "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji" !important;
}

/* Policy */
#onetrust-banner-sdk #onetrust-policy,
#onetrust-banner-sdk.ot-wo-title #onetrust-group-container {
  margin-top: 0px !important;
}

/* Links */
#onetrust-consent-sdk #onetrust-banner-sdk a[href] {
    color: var(--black-500, #3B4045);
    text-decoration: underline;
}
#onetrust-consent-sdk #onetrust-banner-sdk a[href]:hover {
    color: var(--blue-500, #5076f2);
    text-decoration: underline;
}

#onetrust-banner-sdk #onetrust-policy-title {
  padding: 0 0 4px 0 !important;
}

#onetrust-banner-sdk #onetrust-policy-text {
  padding: 0 !important;
  margin-bottom: 8px !important;
  line-height: 1.30769231 !important;
}

/* Buttons */
#onetrust-banner-sdk #onetrust-button-group-parent {
  padding: 0 !important;
}

#onetrust-banner-sdk #onetrust-button-group {
  display: flex !important;
  align-items: start !important;
  gap: 4px;
  margin: 8px 0 0 0;
}


#onetrust-banner-sdk #onetrust-button-group button {
  flex: 0 1 auto;
  white-space: nowrap !important;
  font-weight: bold !important;
  border-radius: 1000px !important;
  padding: 6px 12px !important;
  letter-spacing: normal !important;
  text-decoration: none !important;
  border: 1px solid transparent !important;
  margin: 0 !important;
  line-height: 1.15 !important;
  width: auto !important;
}

#onetrust-banner-sdk #onetrust-button-group button#onetrust-pc-btn-handler {
  background: transparent !important;
  background-color: rgba(0,0,0,.08) !important;
  color: var(--black-600, #201C1D) !important;
  border-color: transparent !important;
}
#onetrust-banner-sdk #onetrust-button-group button#onetrust-pc-btn-handler:hover {
  background-color: rgba(0,0,0,.15) !important;
}


#onetrust-consent-sdk #onetrust-accept-btn-handler {
 background-color: var(--black-600, #201c1d) !important;
  color: var(--white, #ffffff) !important;
}
#onetrust-banner-sdk #onetrust-button-group button#onetrust-reject-all-handler {
  background-color: var(--black-600, #201c1d) !important;
  color: var(--white, #FFFFFF) !important;
}

/* Close button */
#onetrust-banner-sdk #onetrust-close-btn-container {
  top: 0px !important;
  right: 0px  !important;
}

/* Mobile */
@media (max-width: 640px) {
  #onetrust-banner-sdk {
    padding: 16px !important;
    bottom: 16px !important;
  }

  #onetrust-banner-sdk #onetrust-policy {
    padding-top: 0 !important;
    background-image: none !important;
  }

  #onetrust-banner-sdk #onetrust-button-group .banner-actions-container button {
    margin: 8px 0 0 0 !important;
  }

  #onetrust-banner-sdk #onetrust-button-group {
    display: block !important;
  }
  #onetrust-banner-sdk #onetrust-button-group button {
    width: 100% !important;
    margin-top: 8px !important;
  }
}

CommonData.PCCustomCSS:
/* Typography */
#onetrust-pc-sdk.otPcCenter * {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto,
    "Helvetica Neue", Arial, "Noto Sans", sans-serif, "Apple Color Emoji",
    "Segoe UI Emoji", "Segoe UI Symbol", "Noto Color Emoji" !important;
}

/* Buttons */
#onetrust-pc-sdk button#accept-recommended-btn-handler,
#onetrust-pc-sdk button.ot-pc-refuse-all-handler,
#onetrust-pc-sdk button.onetrust-close-btn-handler{
  border-radius: 1000px;
  padding: 10px 16px !important;
  font-size: 14px !important;
  font-weight: bold !important;
  font-synthesis: none !important;
}
#onetrust-pc-sdk .ot-btn-container button {
  letter-spacing: unset !important;
  margin-top: 0px !important;
}
#onetrust-pc-sdk button.ot-pc-refuse-all-handler {
  background-color: var(--black-150, #F0EFED) !important;
  border-color: var(--black-150, #F0EFED) !important;
  color: var(--black-600, #201C1D) !important;
  margin: 0px !important;
}

/* Container */
#onetrust-pc-sdk.otPcCenter {
  margin: 32px auto !important;
  top: 0px !important;
  height: auto !important;
  max-height: 80% !important;
  max-height: calc(100% - 64px) !important;
  overflow: scroll !important;
  border-radius: 10px !important;
  box-shadow:
    0 4px 13px rgba(0, 0, 0, 0.13),
    0 3px 8px rgba(0, 0, 0, 0.09),
    0 1px 4px rgba(0, 0, 0, 0.09) !important;
}

#onetrust-pc-sdk .ot-pc-footer-logo, 
#onetrust-pc-sdk .ot-pc-logo {
    display: none !important;
}

#onetrust-pc-sdk #ot-pc-title {
  font-size: 19px !important;
  font-weight: normal !important;
  margin-top: 0px !important;
}

/* Modal body */
#onetrust-pc-sdk .ot-pc-header {
  height: auto !important;
  padding: 0px !important;
  border-bottom: 0px !important;
}
#onetrust-pc-sdk #ot-pc-content {    
    bottom: 0px !important;
    overflow: visible !important;
    padding: 0px !important;
    position: static !important;
    width: auto !important;
    margin: 24px !important;
}

/* Text */
#onetrust-pc-sdk div#ot-pc-desc {
    margin: 0 !important;
    padding: 0 0 24px !important;
}

/* Pref table */
#onetrust-pc-sdk .ot-cat-grp,
#onetrust-pc-sdk #ot-category-title {
    margin: 0px !important;
    padding: 0px !important;
}

#onetrust-pc-sdk .ot-cat-grp .ot-always-active {
  color: var(--black-600, #201C1D) 
}

#onetrust-pc-sdk .ot-accordion-layout.ot-cat-item {
  border: none !important;
  border-bottom: 1px solid var(--bc-medium, #D6D9DC) !important;
}

#onetrust-pc-sdk .ot-accordion-layout .ot-acc-hdr {
  min-height: auto !important;
  width: 100% !important;
  padding: 8px 0 !important;
  display: flex !important;
  align-items: center !important;
  margin: 0 !important;
}
#onetrust-pc-sdk .ot-accordion-layout .ot-tgl {
  position: static !important;
  transform: none !important;
  height: 25px !important;
  margin-left: auto !important;
}
#onetrust-pc-sdk .ot-accordion-layout .ot-acc-hdr .ot-cat-header {
  font-weight: normal !important;
  padding-left: 0px !important;
}


#onetrust-pc-sdk .ot-plus-minus {
  top: 0px !important;
}

/* Close icon */
#onetrust-pc-sdk #close-pc-btn-handler.ot-close-icon {
 top: 0px !important;
}

/* Policy link */
#onetrust-consent-sdk #onetrust-pc-sdk .privacy-notice-link:hover {
    color: var(--blue-500, #5076f2);
    text-decoration: underline;
}

/* Footer */
#onetrust-pc-sdk .ot-pc-footer {
  max-height: auto !important;
  position: static !important;
  border: 0px !important;
}
